  describe('Performance Metrics', () => {
    describe('getSessionPerformanceStats', () => {
      it('should return session performance metrics', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: 100,
          successCount: 95,
          errorCount: 5,
          processingMode: 'batch',
          batchSize: 100,
          totalDurationMs: 45000,
          avgEmailDurationMs: { toNumber: () => 450 },
          parallelStagesCount: 5,
          databaseBatchOps: 10,
          peakMemoryMb: { toNumber: () => 256.5 },
          createdAt: new Date('2025-01-01T10:00:00Z'),
          updatedAt: new Date('2025-01-01T10:05:00Z'),
        });

        const metrics = await repository.getSessionPerformanceStats(sessionId);

        expect(metrics.emailCount).toBe(100);
        expect(metrics.successCount).toBe(95);
        expect(metrics.errorCount).toBe(5);
        expect(metrics.totalDurationMs).toBe(45000);
        expect(metrics.avgEmailDurationMs).toBe(450);
      });

      it('should throw error if metrics not found', async () => {
        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue(null);

        await expect(repository.getSessionPerformanceStats('999')).rejects.toThrow(
          'Session metrics not found'
        );
      });
    });

    describe('getAverageProcessingTime', () => {
      it('should calculate average processing time across date range', async () => {
        const start = new Date('2025-01-01T00:00:00Z');
        const end = new Date('2025-01-31T23:59:59Z');

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            metrics: { avgEmailDurationMs: { toNumber: () => 400 } },
          },
          {
            sessionId: BigInt(2),
            metrics: { avgEmailDurationMs: { toNumber: () => 600 } },
          },
        ]);

        const avgTime = await repository.getAverageProcessingTime({ start, end });

        expect(avgTime).toBe(500); // (400 + 600) / 2
      });

      it('should return 0 if no sessions in date range', async () => {
        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([]);

        const avgTime = await repository.getAverageProcessingTime({
          start: new Date(),
          end: new Date(),
        });

        expect(avgTime).toBe(0);
      });
    });

