        expect(mockPrisma.classificationSessionError.create).toHaveBeenCalledWith({
          data: {
            sessionId: BigInt(1),
            emailId: emailId,
            errorType: result.error!.type,
            errorMessage: result.error!.message,
            stackTrace: result.error!.stackTrace,
          },
        });
      });
    });

    describe('getBatchProgress', () => {
      it('should return batch progress with percentage', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: 100,
          successCount: 70,
          errorCount: 5,
        });

        (mockPrisma.classificationSession.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'in_progress',
        });

        const progress = await repository.getBatchProgress(sessionId);

        expect(progress).toEqual({
          sessionId: '1',
          totalEmails: 100,
          successCount: 70,
          errorCount: 5,
          progressPercentage: 75, // (70 + 5) / 100 * 100
          isComplete: false,
          status: 'in_progress',
        });
      });

      it('should return 100% progress for completed session', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: 50,
          successCount: 48,
          errorCount: 2,
        });

        (mockPrisma.classificationSession.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'completed',
        });

        const progress = await repository.getBatchProgress(sessionId);

        expect(progress.progressPercentage).toBe(100);
        expect(progress.isComplete).toBe(true);
        expect(progress.status).toBe('completed');
      });

      it('should throw error if session not found', async () => {
        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue(null);

        await expect(repository.getBatchProgress('999')).rejects.toThrow('Session not found');
      });
    });
  });

  describe('Query Operations', () => {
    describe('findSessionById', () => {
