/**
 * Unit tests for SessionRepository (T044 - TDD Approach)
 *
 * Tests session lifecycle management, performance tracking, batch progress updates,
 * analytics queries, and error logging. These tests are written FIRST before
 * implementation following TDD principles.
 *
 * Test Strategy:
 * - Mock Prisma client for unit testing
 * - Test session lifecycle (create, update, complete, abort)
 * - Test batch progress tracking with per-email results
 * - Test query operations (by ID, status, date range)
 * - Test performance metrics aggregation
 * - Test error logging and retrieval
 * - Test edge cases (not found, concurrent updates)
 */

import { SessionRepository } from '../../src/persistence/session-repository';
import { PrismaClient } from '@prisma/client';
import {
  BatchSessionConfig,
  ProgressUpdate,
  SessionSummary,
  EmailResult,
  SessionStatus,
} from '../../src/types/session-types';

// Mock Prisma Client
jest.mock('@prisma/client', () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const mockPrismaClient: any = {
    classificationSession: {
      create: jest.fn(),
      update: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
      findFirst: jest.fn(),
    },
    classificationSessionMetrics: {
      create: jest.fn(),
      update: jest.fn(),
      upsert: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
    },
    classificationSessionError: {
      create: jest.fn(),
      findMany: jest.fn(),
      count: jest.fn(),
    },
    $transaction: jest.fn((callback) => callback(mockPrismaClient)),
    $disconnect: jest.fn(),
  };

  // Mock Prisma Decimal class
  class MockDecimal {
    value: number;
    constructor(value: number | string) {
      this.value = typeof value === 'string' ? parseFloat(value) : value;
    }
    toString() {
      return this.value.toString();
    }
    toNumber() {
      return this.value;
    }
  }

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      Decimal: MockDecimal,
    },
  };
});

describe('SessionRepository', () => {
  let repository: SessionRepository;
  let mockPrisma: jest.Mocked<PrismaClient>;

  beforeEach(() => {
    jest.clearAllMocks();
    repository = new SessionRepository();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockPrisma = (repository as any).prisma;
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('Session Lifecycle Management', () => {
    describe('createBatchSession', () => {
      it('should create a new batch session with metrics', async () => {
        const config: BatchSessionConfig = {
          gmailId: 'msg-batch-001',
          pipelineVersion: 'v1.0.0',
          processingMode: 'batch',
          batchSize: 100,
          triggeredBy: 'cron-job',
        };

        // Mock session creation
        (mockPrisma.classificationSession.create as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          gmailId: config.gmailId,
          pipelineVersion: config.pipelineVersion,
          startedAt: new Date(),
          completedAt: null,
          status: 'in_progress',
          triggeredBy: config.triggeredBy,
        });

        // Mock metrics creation
        (mockPrisma.classificationSessionMetrics.create as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: config.batchSize,
          successCount: 0,
          errorCount: 0,
          processingMode: config.processingMode,
          batchSize: config.batchSize,
        });

        const sessionId = await repository.createBatchSession(config);

        expect(sessionId).toBe('1');
        expect(mockPrisma.$transaction).toHaveBeenCalled();
        expect(mockPrisma.classificationSession.create).toHaveBeenCalledWith({
          data: expect.objectContaining({
            gmailId: config.gmailId,
            pipelineVersion: config.pipelineVersion,
            status: 'in_progress',
            triggeredBy: config.triggeredBy,
          }),
        });
        expect(mockPrisma.classificationSessionMetrics.create).toHaveBeenCalledWith({
          data: expect.objectContaining({
            emailCount: config.batchSize,
            processingMode: config.processingMode,
            batchSize: config.batchSize,
          }),
        });
      });

      it('should rollback transaction if metrics creation fails', async () => {
        const config: BatchSessionConfig = {
          gmailId: 'msg-error',
          pipelineVersion: 'v1.0.0',
          processingMode: 'batch',
          batchSize: 50,
        };

        mockPrisma.$transaction.mockRejectedValue(new Error('Metrics creation failed'));

        await expect(repository.createBatchSession(config)).rejects.toThrow('Failed to create batch session');
        expect(mockPrisma.$transaction).toHaveBeenCalled();
      });
    });

    describe('updateSessionProgress', () => {
      it('should increment success and error counts atomically', async () => {
        const sessionId = '1';
        const update: ProgressUpdate = {
          successCount: 10,
          errorCount: 2,
        };

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          successCount: 10,
          errorCount: 2,
        });

        await repository.updateSessionProgress(sessionId, update);

        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: {
            successCount: { increment: 10 },
            errorCount: { increment: 2 },
            updatedAt: expect.any(Date),
          },
        });
      });

      it('should update parallel stages and batch ops counts', async () => {
        const sessionId = '1';
        const update: ProgressUpdate = {
          parallelStagesCount: 5,
          databaseBatchOps: 3,
        };

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          parallelStagesCount: 5,
          databaseBatchOps: 3,
        });

        await repository.updateSessionProgress(sessionId, update);

        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            parallelStagesCount: { increment: 5 },
            databaseBatchOps: { increment: 3 },
          }),
        });
      });

      it('should throw error if session not found', async () => {
        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockRejectedValue(new Error('Record not found'));

        await expect(repository.updateSessionProgress('999', { successCount: 1 })).rejects.toThrow(
          'Failed to update session progress'
        );
      });
    });

    describe('completeSession', () => {
      it('should complete session with performance metrics', async () => {
        const sessionId = '1';
        const summary: SessionSummary = {
          totalDurationMs: 45000,
          avgEmailDurationMs: 450,
          peakMemoryMb: 256.5,
          finalCategoryId: 10,
          finalConfidence: 0.95,
          finalRationale: 'Batch processing completed successfully',
        };

        // Mock transaction to succeed
        mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));

        (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'completed',
        });

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          totalDurationMs: summary.totalDurationMs,
        });

        await repository.completeSession(sessionId, summary);

        expect(mockPrisma.$transaction).toHaveBeenCalled();
        expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            completedAt: expect.any(Date),
            status: 'completed',
            finalCategoryId: summary.finalCategoryId,
          }),
        });
        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            totalDurationMs: summary.totalDurationMs,
            avgEmailDurationMs: expect.any(Object), // Prisma.Decimal
            peakMemoryMb: expect.any(Object),
          }),
        });
      });
    });

    describe('abortSession', () => {
      it('should mark session as aborted with reason', async () => {
        const sessionId = '1';
        const reason = 'User cancelled batch processing';

        (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'aborted',
          finalRationale: reason,
        });

        await repository.abortSession(sessionId, reason);

        expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: {
            status: 'aborted',
            finalRationale: reason,
            completedAt: expect.any(Date),
          },
        });
      });
    });
  });

  describe('Batch Progress Tracking', () => {
    describe('recordEmailResult', () => {
      it('should increment success count for successful email', async () => {
        const sessionId = '1';
        const emailId = 'msg-001';
        const result: EmailResult = {
          success: true,
          durationMs: 500,
        };

        // Mock transaction to succeed
        mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          successCount: 1,
