/**
 * Unit tests for SessionRepository (T044 - TDD Approach)
 *
 * Tests session lifecycle management, performance tracking, batch progress updates,
 * analytics queries, and error logging. These tests are written FIRST before
 * implementation following TDD principles.
 *
 * Test Strategy:
 * - Mock Prisma client for unit testing
 * - Test session lifecycle (create, update, complete, abort)
 * - Test batch progress tracking with per-email results
 * - Test query operations (by ID, status, date range)
 * - Test performance metrics aggregation
 * - Test error logging and retrieval
 * - Test edge cases (not found, concurrent updates)
 */

import { SessionRepository } from '../../src/persistence/session-repository';
import { PrismaClient } from '@prisma/client';
import {
  BatchSessionConfig,
  ProgressUpdate,
  SessionSummary,
  EmailResult,
  SessionStatus,
} from '../../src/types/session-types';

// Mock Prisma Client
jest.mock('@prisma/client', () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const mockPrismaClient: any = {
    classificationSession: {
      create: jest.fn(),
      update: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
      findFirst: jest.fn(),
    },
    classificationSessionMetrics: {
      create: jest.fn(),
      update: jest.fn(),
      upsert: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
    },
    classificationSessionError: {
      create: jest.fn(),
      findMany: jest.fn(),
      count: jest.fn(),
    },
    $transaction: jest.fn((callback) => callback(mockPrismaClient)),
    $disconnect: jest.fn(),
  };

  // Mock Prisma Decimal class
  class MockDecimal {
    value: number;
    constructor(value: number | string) {
      this.value = typeof value === 'string' ? parseFloat(value) : value;
    }
    toString() {
      return this.value.toString();
    }
    toNumber() {
      return this.value;
    }
  }

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      Decimal: MockDecimal,
    },
  };
});

describe('SessionRepository', () => {
  let repository: SessionRepository;
  let mockPrisma: jest.Mocked<PrismaClient>;

  beforeEach(() => {
    jest.clearAllMocks();
    repository = new SessionRepository();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockPrisma = (repository as any).prisma;
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('Session Lifecycle Management', () => {
    describe('createBatchSession', () => {
      it('should create a new batch session with metrics', async () => {
        const config: BatchSessionConfig = {
          gmailId: 'msg-batch-001',
          pipelineVersion: 'v1.0.0',
          processingMode: 'batch',
          batchSize: 100,
          triggeredBy: 'cron-job',
        };

        // Mock session creation
        (mockPrisma.classificationSession.create as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          gmailId: config.gmailId,
          pipelineVersion: config.pipelineVersion,
          startedAt: new Date(),
          completedAt: null,
          status: 'in_progress',
          triggeredBy: config.triggeredBy,
        });

        // Mock metrics creation
        (mockPrisma.classificationSessionMetrics.create as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: config.batchSize,
          successCount: 0,
          errorCount: 0,
          processingMode: config.processingMode,
          batchSize: config.batchSize,
        });

        const sessionId = await repository.createBatchSession(config);

        expect(sessionId).toBe('1');
        expect(mockPrisma.$transaction).toHaveBeenCalled();
        expect(mockPrisma.classificationSession.create).toHaveBeenCalledWith({
          data: expect.objectContaining({
            gmailId: config.gmailId,
            pipelineVersion: config.pipelineVersion,
            status: 'in_progress',
            triggeredBy: config.triggeredBy,
          }),
        });
        expect(mockPrisma.classificationSessionMetrics.create).toHaveBeenCalledWith({
          data: expect.objectContaining({
            emailCount: config.batchSize,
            processingMode: config.processingMode,
            batchSize: config.batchSize,
          }),
        });
      });

      it('should rollback transaction if metrics creation fails', async () => {
        const config: BatchSessionConfig = {
          gmailId: 'msg-error',
          pipelineVersion: 'v1.0.0',
          processingMode: 'batch',
          batchSize: 50,
        };

        mockPrisma.$transaction.mockRejectedValue(new Error('Metrics creation failed'));

        await expect(repository.createBatchSession(config)).rejects.toThrow('Failed to create batch session');
        expect(mockPrisma.$transaction).toHaveBeenCalled();
      });
    });

    describe('updateSessionProgress', () => {
      it('should increment success and error counts atomically', async () => {
        const sessionId = '1';
        const update: ProgressUpdate = {
          successCount: 10,
          errorCount: 2,
        };

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          successCount: 10,
          errorCount: 2,
        });

        await repository.updateSessionProgress(sessionId, update);

        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: {
            successCount: { increment: 10 },
            errorCount: { increment: 2 },
            updatedAt: expect.any(Date),
          },
        });
      });

      it('should update parallel stages and batch ops counts', async () => {
        const sessionId = '1';
        const update: ProgressUpdate = {
          parallelStagesCount: 5,
          databaseBatchOps: 3,
        };

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          parallelStagesCount: 5,
          databaseBatchOps: 3,
        });

        await repository.updateSessionProgress(sessionId, update);

        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            parallelStagesCount: { increment: 5 },
            databaseBatchOps: { increment: 3 },
          }),
        });
      });

      it('should throw error if session not found', async () => {
        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockRejectedValue(new Error('Record not found'));

        await expect(repository.updateSessionProgress('999', { successCount: 1 })).rejects.toThrow(
          'Failed to update session progress'
        );
      });
    });

    describe('completeSession', () => {
      it('should complete session with performance metrics', async () => {
        const sessionId = '1';
        const summary: SessionSummary = {
          totalDurationMs: 45000,
          avgEmailDurationMs: 450,
          peakMemoryMb: 256.5,
          finalCategoryId: 10,
          finalConfidence: 0.95,
          finalRationale: 'Batch processing completed successfully',
        };

        // Mock transaction to succeed
        mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));

        (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'completed',
        });

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          totalDurationMs: summary.totalDurationMs,
        });

        await repository.completeSession(sessionId, summary);

        expect(mockPrisma.$transaction).toHaveBeenCalled();
        expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            completedAt: expect.any(Date),
            status: 'completed',
            finalCategoryId: summary.finalCategoryId,
          }),
        });
        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            totalDurationMs: summary.totalDurationMs,
            avgEmailDurationMs: expect.any(Object), // Prisma.Decimal
            peakMemoryMb: expect.any(Object),
          }),
        });
      });
    });

    describe('abortSession', () => {
      it('should mark session as aborted with reason', async () => {
        const sessionId = '1';
        const reason = 'User cancelled batch processing';

        (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'aborted',
          finalRationale: reason,
        });

        await repository.abortSession(sessionId, reason);

        expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: {
            status: 'aborted',
            finalRationale: reason,
            completedAt: expect.any(Date),
          },
        });
      });
    });
  });

  describe('Batch Progress Tracking', () => {
    describe('recordEmailResult', () => {
      it('should increment success count for successful email', async () => {
        const sessionId = '1';
        const emailId = 'msg-001';
        const result: EmailResult = {
          success: true,
          durationMs: 500,
        };

        // Mock transaction to succeed
        mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          successCount: 1,
        });

        await repository.recordEmailResult(sessionId, emailId, result);

        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            successCount: { increment: 1 },
          }),
        });
      });

      it('should increment error count and log error for failed email', async () => {
        const sessionId = '1';
        const emailId = 'msg-error-001';
        const result: EmailResult = {
          success: false,
          error: {
            type: 'ClassificationError',
            message: 'Failed to classify email',
            stackTrace: 'Error: Failed...\n  at ...',
          },
          durationMs: 100,
        };

        // Mock transaction to succeed
        mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));

        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          errorCount: 1,
        });

        (mockPrisma.classificationSessionError.create as jest.Mock).mockResolvedValue({
          errorId: BigInt(1),
          sessionId: BigInt(1),
          emailId: emailId,
        });

        await repository.recordEmailResult(sessionId, emailId, result);

        expect(mockPrisma.$transaction).toHaveBeenCalled();
        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
          where: { sessionId: BigInt(1) },
          data: expect.objectContaining({
            errorCount: { increment: 1 },
          }),
        });
        expect(mockPrisma.classificationSessionError.create).toHaveBeenCalledWith({
          data: {
            sessionId: BigInt(1),
            emailId: emailId,
            errorType: result.error!.type,
            errorMessage: result.error!.message,
            stackTrace: result.error!.stackTrace,
          },
        });
      });
    });

    describe('getBatchProgress', () => {
      it('should return batch progress with percentage', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: 100,
          successCount: 70,
          errorCount: 5,
        });

        (mockPrisma.classificationSession.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'in_progress',
        });

        const progress = await repository.getBatchProgress(sessionId);

        expect(progress).toEqual({
          sessionId: '1',
          totalEmails: 100,
          successCount: 70,
          errorCount: 5,
          progressPercentage: 75, // (70 + 5) / 100 * 100
          isComplete: false,
          status: 'in_progress',
        });
      });

      it('should return 100% progress for completed session', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: 50,
          successCount: 48,
          errorCount: 2,
        });

        (mockPrisma.classificationSession.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          status: 'completed',
        });

        const progress = await repository.getBatchProgress(sessionId);

        expect(progress.progressPercentage).toBe(100);
        expect(progress.isComplete).toBe(true);
        expect(progress.status).toBe('completed');
      });

      it('should throw error if session not found', async () => {
        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue(null);

        await expect(repository.getBatchProgress('999')).rejects.toThrow('Session not found');
      });
    });
  });

  describe('Query Operations', () => {
    describe('findSessionById', () => {
      it('should return full session details with metrics', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSession.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          gmailId: 'msg-001',
          pipelineVersion: 'v1.0.0',
          startedAt: new Date('2025-01-01T10:00:00Z'),
          completedAt: new Date('2025-01-01T10:05:00Z'),
          status: 'completed',
          triggeredBy: 'system',
          aiRoutingUsed: false,
          finalCategoryId: 10,
          finalConfidence: { toNumber: () => 0.95 },
          finalRationale: 'Test',
          metrics: {
            sessionId: BigInt(1),
            emailCount: 1,
            successCount: 1,
            errorCount: 0,
            processingMode: 'sequential',
            batchSize: 1,
            totalDurationMs: 5000,
            avgEmailDurationMs: { toNumber: () => 5000 },
            parallelStagesCount: 3,
            databaseBatchOps: 1,
            peakMemoryMb: { toNumber: () => 128.5 },
            createdAt: new Date('2025-01-01T10:00:00Z'),
            updatedAt: new Date('2025-01-01T10:05:00Z'),
          },
        });

        const session = await repository.findSessionById(sessionId);

        expect(session).not.toBeNull();
        expect(session!.sessionId).toBe('1');
        expect(session!.gmailId).toBe('msg-001');
        expect(session!.status).toBe('completed');
        expect(session!.metrics).not.toBeNull();
        expect(session!.metrics!.emailCount).toBe(1);
        expect(session!.metrics!.successCount).toBe(1);
      });

      it('should return null if session not found', async () => {
        (mockPrisma.classificationSession.findUnique as jest.Mock).mockResolvedValue(null);

        const session = await repository.findSessionById('999');

        expect(session).toBeNull();
      });
    });

    describe('findActiveSessions', () => {
      it('should return all in-progress sessions', async () => {
        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            gmailId: 'msg-001',
            pipelineVersion: 'v1.0.0',
            startedAt: new Date(),
            completedAt: null,
            status: 'in_progress',
            triggeredBy: 'system',
            aiRoutingUsed: false,
            finalCategoryId: null,
            finalConfidence: null,
            finalRationale: null,
            metrics: null,
          },
          {
            sessionId: BigInt(2),
            gmailId: 'msg-002',
            pipelineVersion: 'v1.0.0',
            startedAt: new Date(),
            completedAt: null,
            status: 'in_progress',
            triggeredBy: 'user',
            aiRoutingUsed: false,
            finalCategoryId: null,
            finalConfidence: null,
            finalRationale: null,
            metrics: null,
          },
        ]);

        const sessions = await repository.findActiveSessions();

        expect(sessions).toHaveLength(2);
        expect(mockPrisma.classificationSession.findMany).toHaveBeenCalledWith({
          where: { status: 'in_progress' },
          orderBy: { startedAt: 'desc' },
          include: { metrics: true },
        });
      });
    });

    describe('findSessionsByStatus', () => {
      it('should filter sessions by status', async () => {
        const status: SessionStatus = 'completed';

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            status: 'completed',
          },
        ]);

        await repository.findSessionsByStatus(status);

        expect(mockPrisma.classificationSession.findMany).toHaveBeenCalledWith({
          where: { status: status },
          orderBy: { startedAt: 'desc' },
        });
      });
    });

    describe('findSessionsByDateRange', () => {
      it('should filter sessions by date range', async () => {
        const start = new Date('2025-01-01T00:00:00Z');
        const end = new Date('2025-01-31T23:59:59Z');

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            startedAt: new Date('2025-01-15T10:00:00Z'),
          },
        ]);

        await repository.findSessionsByDateRange({ start, end });

        expect(mockPrisma.classificationSession.findMany).toHaveBeenCalledWith({
          where: {
            startedAt: {
              gte: start,
              lte: end,
            },
          },
          orderBy: { startedAt: 'desc' },
        });
      });
    });
  });

  describe('Performance Metrics', () => {
    describe('getSessionPerformanceStats', () => {
      it('should return session performance metrics', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue({
          sessionId: BigInt(1),
          emailCount: 100,
          successCount: 95,
          errorCount: 5,
          processingMode: 'batch',
          batchSize: 100,
          totalDurationMs: 45000,
          avgEmailDurationMs: { toNumber: () => 450 },
          parallelStagesCount: 5,
          databaseBatchOps: 10,
          peakMemoryMb: { toNumber: () => 256.5 },
          createdAt: new Date('2025-01-01T10:00:00Z'),
          updatedAt: new Date('2025-01-01T10:05:00Z'),
        });

        const metrics = await repository.getSessionPerformanceStats(sessionId);

        expect(metrics.emailCount).toBe(100);
        expect(metrics.successCount).toBe(95);
        expect(metrics.errorCount).toBe(5);
        expect(metrics.totalDurationMs).toBe(45000);
        expect(metrics.avgEmailDurationMs).toBe(450);
      });

      it('should throw error if metrics not found', async () => {
        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue(null);

        await expect(repository.getSessionPerformanceStats('999')).rejects.toThrow('Session metrics not found');
      });
    });

    describe('getAverageProcessingTime', () => {
      it('should calculate average processing time across date range', async () => {
        const start = new Date('2025-01-01T00:00:00Z');
        const end = new Date('2025-01-31T23:59:59Z');

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            metrics: { avgEmailDurationMs: { toNumber: () => 400 } },
          },
          {
            sessionId: BigInt(2),
            metrics: { avgEmailDurationMs: { toNumber: () => 600 } },
          },
        ]);

        const avgTime = await repository.getAverageProcessingTime({ start, end });

        expect(avgTime).toBe(500); // (400 + 600) / 2
      });

      it('should return 0 if no sessions in date range', async () => {
        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([]);

        const avgTime = await repository.getAverageProcessingTime({
          start: new Date(),
          end: new Date(),
        });

        expect(avgTime).toBe(0);
      });
    });

    describe('getFailureRate', () => {
      it('should calculate failure rate as percentage', async () => {
        const start = new Date('2025-01-01T00:00:00Z');
        const end = new Date('2025-01-31T23:59:59Z');

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            metrics: { emailCount: 100, successCount: 95, errorCount: 5 },
          },
          {
            sessionId: BigInt(2),
            metrics: { emailCount: 50, successCount: 45, errorCount: 5 },
          },
        ]);

        const failureRate = await repository.getFailureRate({ start, end });

        // Total: 150 emails, 10 failures = 6.67%
        expect(failureRate).toBeCloseTo(6.67, 1);
      });
    });
  });

  describe('Error Management', () => {
    describe('getSessionErrors', () => {
      it('should return all errors for a session', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionError.findMany as jest.Mock).mockResolvedValue([
          {
            errorId: BigInt(1),
            sessionId: BigInt(1),
            emailId: 'msg-error-001',
            errorType: 'ClassificationError',
            errorMessage: 'Failed to classify',
            stackTrace: 'Error: ...',
            occurredAt: new Date(),
          },
          {
            errorId: BigInt(2),
            sessionId: BigInt(1),
            emailId: 'msg-error-002',
            errorType: 'DatabaseError',
            errorMessage: 'Connection timeout',
            stackTrace: 'Error: ...',
            occurredAt: new Date(),
          },
        ]);

        const errors = await repository.getSessionErrors(sessionId);

        expect(errors).toHaveLength(2);
        expect(errors[0].errorType).toBe('ClassificationError');
        expect(errors[1].errorType).toBe('DatabaseError');
      });
    });
  });

  describe('Constructor and Cleanup', () => {
    it('should create repository with default Prisma client', () => {
      const repo = new SessionRepository();
      expect(repo).toBeInstanceOf(SessionRepository);
    });

    it('should create repository with provided Prisma client', () => {
      const externalPrisma = new PrismaClient();
      const repo = new SessionRepository(externalPrisma);
      expect(repo).toBeInstanceOf(SessionRepository);
    });

    it('should close repository and disconnect Prisma', async () => {
      const repo = new SessionRepository();
      await repo.close();

      expect(mockPrisma.$disconnect).toHaveBeenCalled();
    });
  });
});

