     1→/**
     2→ * Session Repository (T044) - Prisma Implementation
     3→ *
     4→ * Repository pattern for session lifecycle management, performance tracking,
     5→ * and analytics queries using Prisma ORM.
     6→ *
     7→ * Separation of Concerns from T043 ClassificationRepository:
     8→ * - T043: Write-heavy classification persistence (commands)
     9→ * - T044: Read-heavy session analytics and lifecycle management (queries)
    10→ *
    11→ * Key Responsibilities:
    12→ * - Session lifecycle management (create, update progress, complete, abort)
    13→ * - Batch processing support (multi-email sessions)
    14→ * - Performance metrics tracking
    15→ * - Error logging and retrieval
    16→ * - Analytics queries (by ID, status, date range, average times, failure rates)
    17→ */
    18→
    19→import { PrismaClient, Prisma } from '@prisma/client';
    20→import {
    21→  BatchSessionConfig,
    22→  ProgressUpdate,
    23→  SessionSummary,
    24→  EmailResult,
    25→  SessionDetails,
    26→  SessionStatus,
    27→  PerformanceMetrics,
    28→  BatchProgress,
    29→  SessionError,
    30→  DateRange,
    31→} from '../types/session-types';
    32→
    33→/**
    34→ * Session Repository using Prisma ORM
    35→ *
    36→ * Provides session lifecycle management with performance tracking,
    37→ * batch progress monitoring, and analytics queries.
    38→ */
    39→export class SessionRepository {
    40→  private readonly prisma: PrismaClient;
    41→  private readonly ownsPrisma: boolean;
    42→
    43→  /**
    44→   * Initialize session repository
    45→   *
    46→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    47→   */
    48→  constructor(prisma?: PrismaClient) {
    49→    if (prisma) {
    50→      this.prisma = prisma;
    51→      this.ownsPrisma = false;
    52→    } else {
    53→      this.prisma = new PrismaClient();
    54→      this.ownsPrisma = true;
    55→    }
    56→  }
    57→
    58→  /**
    59→   * Create a new batch session with performance tracking
    60→   *
    61→   * Creates both the session record and associated metrics in a transaction.
    62→   * Supports multi-email batch processing.
    63→   *
    64→   * @param config - Batch session configuration
    65→   * @returns Session ID as string (safe representation of bigint)
    66→   * @throws {Error} If session creation fails
    67→   */
    68→  async createBatchSession(config: BatchSessionConfig): Promise<string> {
    69→    try {
    70→      const result = await this.prisma.$transaction(async (tx) => {
    71→        // Create session record
    72→        const session = await tx.classificationSession.create({
    73→          data: {
    74→            gmailId: config.gmailId,
    75→            pipelineVersion: config.pipelineVersion,
    76→            startedAt: new Date(),
    77→            status: 'in_progress',
    78→            triggeredBy: config.triggeredBy || 'system',
    79→            aiRoutingUsed: false,
    80→          },
    81→        });
    82→
    83→        // Create metrics record
    84→        await tx.classificationSessionMetrics.create({
    85→          data: {
    86→            sessionId: session.sessionId,
    87→            emailCount: config.batchSize,
    88→            successCount: 0,
    89→            errorCount: 0,
    90→            processingMode: config.processingMode,
    91→            batchSize: config.batchSize,
    92→          },
    93→        });
    94→
    95→        return session.sessionId.toString();
    96→      });
    97→
    98→      return result;
    99→    } catch (error) {
   100→      throw new Error(`Failed to create batch session: ${error instanceof Error ? error.message : String(error)}`);
   101→    }
   102→  }
   103→
   104→  /**
   105→   * Update session progress with atomic increments
   106→   *
   107→   * Increments success/error counts and other metrics atomically.
   108→   * Safe for concurrent updates from parallel processing.
   109→   *
   110→   * @param sessionId - Session identifier as string
   111→   * @param update - Progress update with incremental values
   112→   * @throws {Error} If update fails or session not found
   113→   */
   114→  async updateSessionProgress(sessionId: string, update: ProgressUpdate): Promise<void> {
   115→    try {
   116→      const dbSessionId = BigInt(sessionId);
   117→
   118→      // Build update data with atomic increments
   119→      // eslint-disable-next-line @typescript-eslint/no-explicit-any
   120→      const updateData: any = {
   121→        updatedAt: new Date(),
   122→      };
   123→
   124→      if (update.successCount !== undefined) {
   125→        updateData.successCount = { increment: update.successCount };
   126→      }
   127→      if (update.errorCount !== undefined) {
   128→        updateData.errorCount = { increment: update.errorCount };
   129→      }
   130→      if (update.parallelStagesCount !== undefined) {
   131→        updateData.parallelStagesCount = { increment: update.parallelStagesCount };
   132→      }
   133→      if (update.databaseBatchOps !== undefined) {
   134→        updateData.databaseBatchOps = { increment: update.databaseBatchOps };
   135→      }
   136→
   137→      await this.prisma.classificationSessionMetrics.update({
   138→        where: { sessionId: dbSessionId },
   139→        data: updateData,
   140→      });
   141→    } catch (error) {
   142→      throw new Error(
   143→        `Failed to update session progress for ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   144→      );
   145→    }
   146→  }
   147→
   148→  /**
   149→   * Complete a session with final performance metrics
   150→   *
   151→   * Updates session status to 'completed' and stores final performance metrics.
   152→   * Uses transaction to ensure both session and metrics are updated atomically.
   153→   *
   154→   * @param sessionId - Session identifier as string
   155→   * @param summary - Session summary with performance metrics
   156→   * @throws {Error} If completion fails
   157→   */
   158→  async completeSession(sessionId: string, summary: SessionSummary): Promise<void> {
   159→    try {
   160→      const dbSessionId = BigInt(sessionId);
   161→
   162→      await this.prisma.$transaction(async (tx) => {
   163→        // Update session record
   164→        await tx.classificationSession.update({
   165→          where: { sessionId: dbSessionId },
   166→          data: {
   167→            completedAt: new Date(),
   168→            status: 'completed',
   169→            finalCategoryId: summary.finalCategoryId || null,
   170→            finalConfidence: summary.finalConfidence ? new Prisma.Decimal(summary.finalConfidence) : null,
   171→            finalRationale: summary.finalRationale || null,
   172→          },
   173→        });
   174→
   175→        // Update metrics record
   176→        await tx.classificationSessionMetrics.update({
   177→          where: { sessionId: dbSessionId },
   178→          data: {
   179→            totalDurationMs: summary.totalDurationMs,
   180→            avgEmailDurationMs: summary.avgEmailDurationMs ? new Prisma.Decimal(summary.avgEmailDurationMs) : null,
   181→            peakMemoryMb: summary.peakMemoryMb ? new Prisma.Decimal(summary.peakMemoryMb) : null,
   182→            updatedAt: new Date(),
   183→          },
   184→        });
   185→      });
   186→    } catch (error) {
   187→      throw new Error(
   188→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   189→      );
   190→    }
   191→  }
   192→
   193→  /**
   194→   * Abort a session with reason
   195→   *
   196→   * Marks session as 'aborted' and records the reason.
   197→   *
   198→   * @param sessionId - Session identifier as string
   199→   * @param reason - Reason for aborting
   200→   * @throws {Error} If abort fails
   201→   */
   202→  async abortSession(sessionId: string, reason: string): Promise<void> {
   203→    try {
   204→      const dbSessionId = BigInt(sessionId);
   205→
   206→      await this.prisma.classificationSession.update({
   207→        where: { sessionId: dbSessionId },
