   216→        `Failed to abort session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   217→      );
   218→    }
   219→  }
   220→
   221→  /**
   222→   * Record result for individual email in batch
   223→   *
   224→   * Increments success/error counts and logs errors for failed emails.
   225→   * Uses transaction to ensure atomic updates.
   226→   *
   227→   * @param sessionId - Session identifier as string
   228→   * @param emailId - Email identifier
   229→   * @param result - Email processing result
   230→   * @throws {Error} If recording fails
   231→   */
   232→  async recordEmailResult(sessionId: string, emailId: string, result: EmailResult): Promise<void> {
   233→    try {
   234→      const dbSessionId = BigInt(sessionId);
   235→
   236→      await this.prisma.$transaction(async (tx) => {
   237→        // Update metrics
   238→        if (result.success) {
   239→          await tx.classificationSessionMetrics.update({
   240→            where: { sessionId: dbSessionId },
   241→            data: {
   242→              successCount: { increment: 1 },
   243→              updatedAt: new Date(),
   244→            },
   245→          });
   246→        } else {
   247→          // Increment error count
   248→          await tx.classificationSessionMetrics.update({
   249→            where: { sessionId: dbSessionId },
   250→            data: {
   251→              errorCount: { increment: 1 },
   252→              updatedAt: new Date(),
   253→            },
   254→          });
   255→
   256→          // Log error
   257→          if (result.error) {
   258→            await tx.classificationSessionError.create({
   259→              data: {
   260→                sessionId: dbSessionId,
   261→                emailId: emailId,
   262→                errorType: result.error.type,
   263→                errorMessage: result.error.message,
   264→                stackTrace: result.error.stackTrace || null,
   265→              },
   266→            });
   267→          }
   268→        }
   269→      });
   270→    } catch (error) {
   271→      throw new Error(
   272→        `Failed to record email result for ${emailId}: ${error instanceof Error ? error.message : String(error)}`
   273→      );
   274→    }
   275→  }
   276→
   277→  /**
   278→   * Get batch progress for a session
   279→   *
   280→   * Calculates progress percentage and completion status.
   281→   *
   282→   * @param sessionId - Session identifier as string
   283→   * @returns Batch progress summary
   284→   * @throws {Error} If session not found
   285→   */
   286→  async getBatchProgress(sessionId: string): Promise<BatchProgress> {
   287→    const dbSessionId = BigInt(sessionId);
   288→
   289→    const metrics = await this.prisma.classificationSessionMetrics.findUnique({
   290→      where: { sessionId: dbSessionId },
   291→    });
   292→
   293→    if (!metrics) {
