   300→
   301→    if (!session) {
   302→      throw new Error(`Session not found: ${sessionId}`);
   303→    }
   304→
   305→    const totalProcessed = metrics.successCount + metrics.errorCount;
   306→    const progressPercentage = metrics.emailCount > 0 ? Math.round((totalProcessed / metrics.emailCount) * 100) : 0;
   307→
   308→    return {
   309→      sessionId: sessionId,
   310→      totalEmails: metrics.emailCount,
   311→      successCount: metrics.successCount,
   312→      errorCount: metrics.errorCount,
   313→      progressPercentage: progressPercentage,
   314→      isComplete: session.status === 'completed' || session.status === 'aborted',
   315→      status: session.status as SessionStatus,
   316→    };
   317→  }
   318→
   319→  /**
   320→   * Find session by ID with full details including metrics
   321→   *
   322→   * @param sessionId - Session identifier as string
   323→   * @returns Session details with metrics or null if not found
   324→   */
   325→  async findSessionById(sessionId: string): Promise<SessionDetails | null> {
   326→    const dbSessionId = BigInt(sessionId);
