   423→      batchSize: metrics.batchSize,
   424→      totalDurationMs: metrics.totalDurationMs,
   425→      avgEmailDurationMs: metrics.avgEmailDurationMs ? metrics.avgEmailDurationMs.toNumber() : null,
   426→      parallelStagesCount: metrics.parallelStagesCount,
   427→      databaseBatchOps: metrics.databaseBatchOps,
   428→      peakMemoryMb: metrics.peakMemoryMb ? metrics.peakMemoryMb.toNumber() : null,
   429→      createdAt: metrics.createdAt,
