   433→
   434→  /**
   435→   * Calculate average processing time across sessions in date range
   436→   *
   437→   * @param dateRange - Start and end dates (inclusive)
   438→   * @returns Average email processing time in milliseconds
   439→   */
   440→  async getAverageProcessingTime(dateRange: DateRange): Promise<number> {
   441→    const sessions = await this.prisma.classificationSession.findMany({
   442→      where: {
   443→        startedAt: {
   444→          gte: dateRange.start,
   445→          lte: dateRange.end,
   446→        },
   447→      },
   448→      include: {
   449→        metrics: true,
   450→      },
   451→    });
   452→
   453→    if (sessions.length === 0) {
   454→      return 0;
   455→    }
   456→
   457→    const avgTimes = sessions
   458→      .map((s) => s.metrics?.avgEmailDurationMs?.toNumber())
   459→      .filter((time): time is number => time !== undefined && time !== null);
   460→
   461→    if (avgTimes.length === 0) {
   462→      return 0;
   463→    }
   464→
   465→    const sum = avgTimes.reduce((acc, time) => acc + time, 0);
   466→    return sum / avgTimes.length;
   467→  }
   468→
   469→  /**
   470→   * Calculate failure rate across sessions in date range
   471→   *
   472→   * @param dateRange - Start and end dates (inclusive)
   473→   * @returns Failure rate as percentage (0-100)
   474→   */
   475→  async getFailureRate(dateRange: DateRange): Promise<number> {
   476→    const sessions = await this.prisma.classificationSession.findMany({
   477→      where: {
   478→        startedAt: {
   479→          gte: dateRange.start,
   480→          lte: dateRange.end,
