   551→      triggeredBy: session.triggeredBy,
   552→      aiRoutingUsed: session.aiRoutingUsed,
   553→      finalCategoryId: session.finalCategoryId,
   554→      finalConfidence: session.finalConfidence ? session.finalConfidence.toNumber() : null,
   555→      finalRationale: session.finalRationale,
   556→      metrics: session.metrics
   557→        ? {
   558→            emailCount: session.metrics.emailCount,
   559→            successCount: session.metrics.successCount,
   560→            errorCount: session.metrics.errorCount,
   561→            processingMode: session.metrics.processingMode as 'sequential' | 'parallel' | 'batch' | null,
   562→            batchSize: session.metrics.batchSize,
