/**
 * TypeScript types for SessionRepository (T044)
 *
 * Defines interfaces for session lifecycle management, performance tracking,
 * and analytics queries. These types bridge the gap between ClassificationSession
 * type and database schema with performance metrics.
 */

/**
 * Processing mode for classification sessions
 */
export type ProcessingMode = 'sequential' | 'parallel' | 'batch';

/**
 * Session status
 */
export type SessionStatus = 'in_progress' | 'completed' | 'aborted';

/**
 * Configuration for creating a new batch session
 */
export interface BatchSessionConfig {
  /** Gmail message ID (for single email sessions, use this as primary) */
  gmailId: string;
  /** Pipeline version identifier */
  pipelineVersion: string;
  /** Processing mode */
  processingMode: ProcessingMode;
  /** Batch size (number of emails to process) */
  batchSize: number;
  /** User/system that triggered this session */
  triggeredBy?: string;
}

/**
 * Progress update for incrementing session metrics
 */
export interface ProgressUpdate {
  /** Increment success count by this amount */
  successCount?: number;
  /** Increment error count by this amount */
  errorCount?: number;
  /** Update parallel stages count */
  parallelStagesCount?: number;
  /** Update database batch operations count */
  databaseBatchOps?: number;
}

/**
 * Session summary for completion
 */
export interface SessionSummary {
  /** Total duration in milliseconds */
  totalDurationMs: number;
  /** Average email processing duration in milliseconds */
  avgEmailDurationMs?: number;
  /** Peak memory usage in MB */
  peakMemoryMb?: number;
  /** Final category ID (for single-email sessions) */
  finalCategoryId?: number;
  /** Final confidence score */
  finalConfidence?: number;
  /** Final rationale */
  finalRationale?: string;
}

/**
 * Email processing result for batch tracking
 */
export interface EmailResult {
  /** Success or failure */
  success: boolean;
  /** Error information (if failed) */
  error?: {
    type: string;
    message: string;
    stackTrace?: string;
  };
  /** Processing duration in milliseconds */
  durationMs: number;
}

/**
 * Full session details including metrics and base session data
 */
export interface SessionDetails {
  /** Session ID */
  sessionId: string;
  /** Gmail message ID */
  gmailId: string;
  /** Pipeline version */
  pipelineVersion: string;
  /** Session start time */
  startedAt: Date;
  /** Session completion time */
  completedAt: Date | null;
  /** Session status */
  status: SessionStatus;
  /** Who triggered the session */
  triggeredBy: string;
  /** Whether AI routing was used */
  aiRoutingUsed: boolean;
  /** Final category ID (if completed) */
  finalCategoryId: number | null;
  /** Final confidence score */
  finalConfidence: number | null;
  /** Final rationale */
  finalRationale: string | null;
  /** Performance metrics */
  metrics: PerformanceMetrics | null;
}

/**
 * Performance metrics for a session
 */
export interface PerformanceMetrics {
  /** Total number of emails processed */
  emailCount: number;
  /** Number of successful emails */
  successCount: number;
  /** Number of failed emails */
  errorCount: number;
  /** Processing mode used */
  processingMode: ProcessingMode | null;
  /** Batch size */
  batchSize: number | null;
  /** Total duration in milliseconds */
  totalDurationMs: number | null;
  /** Average email processing duration */
  avgEmailDurationMs: number | null;
  /** Number of parallel stages executed */
  parallelStagesCount: number | null;
  /** Number of database batch operations */
  databaseBatchOps: number | null;
  /** Peak memory usage in MB */
  peakMemoryMb: number | null;
  /** Metrics creation time */
  createdAt: Date;
  /** Last update time */
  updatedAt: Date;
}

/**
 * Batch progress tracking
 */
export interface BatchProgress {
  /** Session ID */
  sessionId: string;
  /** Total emails in batch */
  totalEmails: number;
  /** Successfully processed emails */
  successCount: number;
  /** Failed emails */
  errorCount: number;
  /** Progress percentage (0-100) */
  progressPercentage: number;
  /** Is session complete */
  isComplete: boolean;
  /** Session status */
  status: SessionStatus;
}

/**
 * Session error record
 */
export interface SessionError {
  /** Error ID */
  errorId: string;
  /** Session ID */
  sessionId: string;
  /** Email ID (if error was for specific email) */
  emailId: string | null;
  /** Error type */
  errorType: string | null;
  /** Error message */
  errorMessage: string | null;
  /** Stack trace */
  stackTrace: string | null;
  /** When error occurred */
  occurredAt: Date;
}

/**
 * Date range filter for queries
 */
export interface DateRange {
  /** Start date (inclusive) */
  start: Date;
  /** End date (inclusive) */
  end: Date;
}

