/**
 * Unit Tests for DigestGenerator (T046) - TDD Approach
 *
 * Tests cover:
 * - Category grouping logic
 * - Template data preparation
 * - HTML generation using TemplateEngine
 * - Performance optimization
 * - Error handling and edge cases
 *
 * IMPORTANT: These tests should FAIL initially (TDD requirement)
 * Implementation will be done AFTER tests are written
 */

import { DigestGenerator } from '../../src/digest/digest-generator';
import { TemplateEngine } from '../../src/digest/template-engine';
import { PrismaClient } from '@prisma/client';
import type {
  EmailDigest,
  DigestCategory,
  DigestEmail,
  DigestCategoryTemplateData,
} from '../../src/types/email-digest';

// Mock dependencies
jest.mock('../../src/digest/template-engine');
jest.mock('@prisma/client');

describe('DigestGenerator (T046)', () => {
  let digestGenerator: DigestGenerator;
  let mockPrisma: jest.Mocked<PrismaClient>;
  let mockTemplateEngine: jest.Mocked<TemplateEngine>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create mock Prisma client
    mockPrisma = {
      category: {
        findMany: jest.fn(),
      },
      gmailMessage: {
        findMany: jest.fn(),
      },
      classificationSession: {
        findMany: jest.fn(),
      },
      sessionCategory: {
        findMany: jest.fn(),
      },
    } as unknown as jest.Mocked<PrismaClient>;

    // Create mock TemplateEngine
    mockTemplateEngine = {
      compile: jest.fn(),
      loadTemplate: jest.fn(),
      registerPartial: jest.fn(),
    } as unknown as jest.Mocked<TemplateEngine>;

    // Initialize DigestGenerator with mocks
    digestGenerator = new DigestGenerator(mockPrisma, mockTemplateEngine);
  });

  describe('Category Grouping Logic', () => {
    it('should group emails by primary category', async () => {
      // Setup: Mock database response with multiple emails in different categories
      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([
        {
          messageId: 'msg-001',
          subject: 'Invoice from Acme Corp',
          fromEmail: 'billing@acme.com',
          receivedAt: new Date('2025-10-10T10:00:00Z'),
          bodySnippet: 'Your invoice for October...',
        },
        {
          messageId: 'msg-002',
          subject: 'Newsletter: Tech Updates',
          fromEmail: 'news@tech.com',
          receivedAt: new Date('2025-10-10T11:00:00Z'),
          bodySnippet: 'Latest technology news...',
        },
        {
          messageId: 'msg-003',
          subject: 'Receipt from Amazon',
          fromEmail: 'orders@amazon.com',
          receivedAt: new Date('2025-10-10T12:00:00Z'),
          bodySnippet: 'Thank you for your order...',
        },
      ]);

      (mockPrisma.sessionCategory.findMany as jest.Mock).mockResolvedValue([
        { gmailId: 'msg-001', categoryId: 1, isPrimary: true, confidence: 0.95 },
        { gmailId: 'msg-002', categoryId: 2, isPrimary: true, confidence: 0.88 },
        { gmailId: 'msg-003', categoryId: 1, isPrimary: true, confidence: 0.92 },
      ]);

      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'financial', displayName: 'Financial', priority: 1 },
        { categoryId: 2, code: 'newsletters', displayName: 'Newsletters', priority: 5 },
      ]);

      const dateRange = {
        start: new Date('2025-10-10T00:00:00Z'),
        end: new Date('2025-10-10T23:59:59Z'),
      };

      const digest = await digestGenerator.generateDigest({
        digestType: 'daily',
        dateRange,
        recipientEmail: 'user@example.com',
      });

      // Assertions: Should have 2 categories (financial and newsletters)
      expect(digest.categories).toHaveLength(2);

      const financialCategory = digest.categories.find((c) => c.categoryName === 'financial');
      expect(financialCategory).toBeDefined();
      expect(financialCategory?.emailCount).toBe(2); // msg-001 and msg-003

      const newslettersCategory = digest.categories.find((c) => c.categoryName === 'newsletters');
      expect(newslettersCategory).toBeDefined();
      expect(newslettersCategory?.emailCount).toBe(1); // msg-002
    });

    it('should sort categories by priority', async () => {
      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'newsletters', displayName: 'Newsletters', priority: 5 },
        { categoryId: 2, code: 'financial', displayName: 'Financial', priority: 1 },
        { categoryId: 3, code: 'social', displayName: 'Social', priority: 3 },
      ]);

      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([
        { messageId: 'msg-001', subject: 'Test 1' },
        { messageId: 'msg-002', subject: 'Test 2' },
        { messageId: 'msg-003', subject: 'Test 3' },
      ]);

      (mockPrisma.sessionCategory.findMany as jest.Mock).mockResolvedValue([
        { gmailId: 'msg-001', categoryId: 1, isPrimary: true },
        { gmailId: 'msg-002', categoryId: 2, isPrimary: true },
        { gmailId: 'msg-003', categoryId: 3, isPrimary: true },
      ]);

      const digest = await digestGenerator.generateDigest({
        digestType: 'daily',
        dateRange: { start: new Date(), end: new Date() },
        recipientEmail: 'user@example.com',
      });

      // Should be sorted by priority: Financial (1), Social (3), Newsletters (5)
      expect(digest.categories[0].categoryName).toBe('financial');
      expect(digest.categories[1].categoryName).toBe('social');
      expect(digest.categories[2].categoryName).toBe('newsletters');
    });

    it('should handle emails with multiple categories (primary + secondary)', async () => {
      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([
        { messageId: 'msg-001', subject: 'Invoice and Receipt' },
      ]);

      (mockPrisma.sessionCategory.findMany as jest.Mock).mockResolvedValue([
        { gmailId: 'msg-001', categoryId: 1, isPrimary: true, confidence: 0.85 },
        { gmailId: 'msg-001', categoryId: 2, isPrimary: false, confidence: 0.65 },
      ]);

      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'financial', displayName: 'Financial', priority: 1 },
        { categoryId: 2, code: 'receipts', displayName: 'Receipts', priority: 2 },
      ]);

      const digest = await digestGenerator.generateDigest({
        digestType: 'daily',
        dateRange: { start: new Date(), end: new Date() },
        recipientEmail: 'user@example.com',
      });

      // Email should appear in primary category (financial) only
      const financialCategory = digest.categories.find((c) => c.categoryName === 'financial');
      expect(financialCategory?.emailCount).toBe(1);

      // Email's DigestEmail object should list both categories
      const email = financialCategory?.emails[0];
      expect(email?.categories).toEqual(['financial', 'receipts']);
    });
  });

  describe('Template Data Preparation', () => {
    it('should prepare category template data with all required fields', async () => {
      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'financial', displayName: 'Financial', priority: 1, description: 'Financial emails' },
      ]);

      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([
        {
          messageId: 'msg-001',
          subject: 'Invoice',
          fromEmail: 'billing@example.com',
          fromRaw: 'Billing <billing@example.com>',
          receivedAt: new Date('2025-10-10T10:00:00Z'),
          bodySnippet: 'Your invoice...',
        },
      ]);

      (mockPrisma.sessionCategory.findMany as jest.Mock).mockResolvedValue([
        { gmailId: 'msg-001', categoryId: 1, isPrimary: true, confidence: 0.95 },
      ]);

      const digest = await digestGenerator.generateDigest({
        digestType: 'daily',
        dateRange: { start: new Date(), end: new Date() },
        recipientEmail: 'user@example.com',
      });

      const categoryTemplateData = digest.categories[0].templateData;

      expect(categoryTemplateData).toMatchObject({
        name: 'financial',
        displayName: 'Financial',
        description: 'Financial emails',
        totalCount: 1,
        iconClass: expect.any(String),
        colorScheme: expect.any(String),
        sortOrder: 1,
        statistics: {
          emailCount: 1,
          averageConfidence: 0.95,
          urgentEmailsCount: expect.any(Number),
          aiClassifiedCount: expect.any(Number),
          averageProcessingTime: expect.any(Number),
          topDomains: expect.any(Array),
        },
      });
    });

    it('should group emails within categories by urgency level', async () => {
      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'financial', displayName: 'Financial', priority: 1 },
      ]);

      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([
        { messageId: 'msg-001', subject: 'Urgent Payment Due' },
        { messageId: 'msg-002', subject: 'Regular Statement' },
        { messageId: 'msg-003', subject: 'Receipt' },
      ]);

      (mockPrisma.sessionCategory.findMany as jest.Mock).mockResolvedValue([
        { gmailId: 'msg-001', categoryId: 1, isPrimary: true },
        { gmailId: 'msg-002', categoryId: 1, isPrimary: true },
        { gmailId: 'msg-003', categoryId: 1, isPrimary: true },
      ]);

      // Mock urgency detection
      (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
        { gmailId: 'msg-001', sessionId: 1n },
        { gmailId: 'msg-002', sessionId: 2n },
        { gmailId: 'msg-003', sessionId: 3n },
      ]);

      // Mock detected attributes for urgency
      mockPrisma.detectedAttribute = {
