      });

      // Should properly escape special characters
      const email = digest.categories[0]?.emails[0];
      expect(email?.subject).not.toContain('<script>');
    });
  });

  describe('DigestGenerator Integration', () => {
    it('should create complete EmailDigest with all required fields', async () => {
      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'financial', displayName: 'Financial', priority: 1 },
